from datetime import timedelta

# Contractual SLA timers by severity (start from detected_at on our side,
# OR from vendor's first notification — whichever is earlier)
RESPONSE_SLA: dict[IncidentSeverity, dict[str, timedelta]] = {
    IncidentSeverity.SEV1_CRITICAL: {
        "vendor_acknowledge":   timedelta(hours=1),
        "initial_status_update": timedelta(hours=2),
        "containment_eta":       timedelta(hours=4),
        "rca_delivered":         timedelta(days=5),
        "remediation_complete":  timedelta(days=14),
    },
    IncidentSeverity.SEV2_HIGH: {
        "vendor_acknowledge":   timedelta(hours=4),
        "initial_status_update": timedelta(hours=8),
        "containment_eta":       timedelta(hours=24),
        "rca_delivered":         timedelta(days=10),
        "remediation_complete":  timedelta(days=30),
    },
    IncidentSeverity.SEV3_MODERATE: {
        "vendor_acknowledge":   timedelta(hours=24),
        "initial_status_update": timedelta(hours=48),
        "rca_delivered":         timedelta(days=30),
        "remediation_complete":  timedelta(days=60),
    },
    IncidentSeverity.SEV4_LOW: {
        "vendor_acknowledge":   timedelta(days=5),
        "rca_delivered":         timedelta(days=60),
    },
}

def check_sla_breaches(incident: VendorIncident) -> list[str]:
    """Return list of SLA milestones that have been missed."""
    slas = RESPONSE_SLA.get(incident.severity, {})
    breaches = []
    now = datetime.utcnow()
    for milestone, allowed_delta in slas.items():
        deadline = incident.detected_at + allowed_delta
        if now > deadline:
            # Check timeline for this milestone being logged
            achieved = any(milestone in e["note"] for e in incident.timeline)
            if not achieved:
                overdue_hours = (now - deadline).total_seconds() / 3600
                breaches.append(
                    f"{milestone}: overdue by {overdue_hours:.1f}h "
                    f"(deadline was {deadline.strftime('%Y-%m-%d %H:%M')} UTC)"
                )
    return breaches

from enum import auto

class FallbackStrategy(str, Enum):
    DEGRADE_GRACEFULLY = "degrade_gracefully"  # return cached / simplified output
    ROUTE_TO_BACKUP    = "route_to_backup"      # secondary LLM provider
    QUEUE_FOR_RETRY    = "queue_for_retry"      # hold request; retry after window
    HUMAN_HANDOFF      = "human_handoff"        # escalate to human reviewer

@dataclass
class VendorFallbackConfig:
    vendor_id: str
    primary_endpoint: str
    strategy: FallbackStrategy
    backup_vendor_id: Optional[str] = None
    backup_endpoint:  Optional[str] = None
    max_queue_minutes: int = 30

class FallbackRouter:
    def __init__(self, configs: list[VendorFallbackConfig]):
        self._configs = {c.vendor_id: c for c in configs}

    def handle_outage(self, vendor_id: str, request: dict) -> dict:
        cfg = self._configs.get(vendor_id)
        if not cfg:
            raise ValueError(f"No fallback configured for vendor {vendor_id}")

        if cfg.strategy == FallbackStrategy.ROUTE_TO_BACKUP and cfg.backup_endpoint:
            import httpx
            resp = httpx.post(cfg.backup_endpoint, json=request, timeout=30)
            return {"source": "backup", "vendor": cfg.backup_vendor_id,
                    "data": resp.json()}

        if cfg.strategy == FallbackStrategy.DEGRADE_GRACEFULLY:
            return {"source": "degraded", "message":
                    "AI service temporarily unavailable. Showing cached result."}

        if cfg.strategy == FallbackStrategy.HUMAN_HANDOFF:
            queue_for_human_review(request)
            return {"source": "queued", "message":
                    "Your request has been queued for human review."}

        return {"source": "unavailable", "message": "Service temporarily unavailable."}
